"""
MKT Original Language Commentary — Genesis chapters 46–48
Run: python3 scripts/zc-original-genesis-46-48.py

Source data used:
- data/interlinear/genesis.json
- data/translation/glossary-hebrew.json (key terms: nāsaʿ, gûr, mĕgûrîm, ḥesed, śākal, gāʾal)
- data/translation/draft/mediating/genesis.json (MKT text)

Key decisions in this range:
- Ch46:v27 — 70 vs. 75 discrepancy (LXX adds 5; Acts 7:14 follows LXX; Deut 10:22 has 70)
  noted as manuscript/counting-tradition difference
- Ch47:v9 mĕgûrāy (pilgrimage/sojourning) — the gûr root is the covenant-gēr word;
  links Jacob's self-description to the patriarchal pilgrim-identity
- Ch47:v29 ḥesed weʾĕmet — the covenant word-pair explained
- Ch47:v31 miṭṭāh — "bed" (MT vowels) vs. "staff" (LXX/Heb 11:21) — textual variant noted
- Ch48:v14 śikel (crossed hands) — Piel of śākal (to act with wisdom/insight); deliberate reversal
- Ch48:v15 rōʿeh (shepherd) as divine epithet — participial, first in God-as-shepherd tradition
- Ch48:v16 gāʾal (redeem) — first use of the kinsman-redeemer verb for the divine agent
- Ch48:v19 mĕlōʾ-haggôyim (fullness of nations) — hapax in this sense; Rom 11:25 is different
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS_ORIGINAL = {
  "46": {
    "1": """<p><strong>wayyisaʿ</strong> — waw-consecutive Qal imperfect of <em>nāsaʿ</em> (to pull up tent-pegs, break camp, set out). The term is the technical vocabulary of nomadic movement: pulling the tent-pegs signals the departure of the entire camp. <strong>ʾĕlōhê ʾāḇîw yiṣḥāq</strong> — "the God of his father Isaac": the patriarchal covenant-designation locates YHWH within the father-to-son covenantal chain rather than as an abstract deity. The relational genealogy of the divine name is the covenant-formula.</p>""",
    "2": """<p><strong>bĕmarʾōt hallaylāh</strong> — "in night visions" (<em>marʾôt</em>, plural of <em>marʾeh</em>, vision/appearance); the plural is an intensive form indicating the vividness or multiplicity of the vision experience. <strong>Yaʿăqōḇ yaʿăqōḇ</strong> — the double-name call (also 22:11 Abraham; Exod 3:4 Moses; 1 Sam 3:10 Samuel) is the theophanic urgency formula. <strong>hinnēnî</strong> — Jacob's response of total covenantal availability; the same word used by Abraham at the Akedah (22:1,7,11).</p>""",
    "3": """<p><strong>ʾānōkî hāʾēl</strong> — "I am the God" with the definite article (<em>hāʾēl</em>). The article on <em>ʾēl</em> is unusual; it specifies the particular divine identity against any other use of the title <em>ʾēl</em> in the surrounding Canaanite/Egyptian context. <strong>ʾal-tîrāʾ</strong> — the reassurance-formula of covenant-initiation encounters (also 26:24 to Isaac; 46:3; Isa 41:10); its appearance marks this as a structurally parallel theophany to the covenant-renewals of Abraham (15:1) and Isaac (26:24).</p>""",
    "4": """<p><strong>ʾānōkî ʾērēḏ ʿimmĕkā</strong> — "I myself will go down with you" (<em>ānōkî</em> is emphatic: "I, personally"). The divine descent-promise uses the same <em>yāraḏ</em> (go down) vocabulary as YHWH's judicial descents (11:5; 18:21); here it is a presence-promise, not a judgment-descent. <strong>ʿālōh ʾaʿaʿlĕkā</strong> — infinitive absolute + finite verb: "I will surely bring you up" — the double-verb construction is the Hebrew idiom for absolute certainty (cf. <em>mōt tāmût</em>, "you will surely die," 2:17). The word "bring up" (<em>ʿālāh</em>) anticipates the Exodus (<em>ʿālāh</em> from Egypt).</p>""",
    "5": """<p><strong>hāʿăgālōt</strong> — "the carts/wagons" (<em>ʿăgālāh</em>, wheeled vehicle). The term is significant in later OT narrative: the Philistines will use an <em>ʿăgālāh</em> to return the Ark (1 Sam 6:7-12), and David's initial ark-transport used an <em>ʿăgālāh</em> with fatal consequences (2 Sam 6:3). The Egyptian-supplied carts as the vehicle for Jacob's Egypt-descent is a narrative marker of Pharaoh's genuine provision for the covenant-family at this point in Joseph's story.</p>""",
    "6": """<p><strong>ûḇēn-bĕnāyw</strong> — "and his grandsons with him" alongside "his daughters and granddaughters" (<em>bĕnōtāyw ûḇĕnôt bānāyw</em>). The verse's Hebrew lists four generations: Jacob himself, sons, grandsons, daughters/granddaughters — the comprehensive household unit. The repetition of "all his descendants" (<em>kol-zarʿô</em>, all his seed) across vv6-7 emphasizes the totality of the covenant-family's migration: no branch of the Abrahamic promise stays behind.</p>""",
    "7": """<p><strong>bānāyw ûḇnê-bānāyw ʾittô</strong> — sons and grandsons; <strong>bĕnōtāyw ûḇĕnôt bānāyw</strong> — daughters and granddaughters. The genealogical formula is structured by gender pairs: male line first (sons, grandsons), then female line (daughters, granddaughters). The inclusivity of the formula — explicitly naming both male and female descendants — is notable; the numerical count that follows (vv8-27) will count males in the genealogical list, but this verse establishes that "all his descendants" includes both sexes.</p>""",
    "8": """<p><strong>ʾēlleh šĕmôt bĕnê yiśrāʾēl</strong> — "these are the names of the sons of Israel" — the genealogical header formula that will recur verbatim at the beginning of Exodus (Exod 1:1: <em>wĕʾēlleh šĕmôt bĕnê yiśrāʾēl</em>). The echo is deliberate: the genealogy of those who "went to Egypt" in Genesis 46 is the genealogy of those who "were in Egypt" at the start of Exodus. The name-list of the seventy is the literary bridge between the patriarchal and Mosaic eras.</p>""",
    "9": """<p>The sons of Reuben: <strong>Ḥănôk wĕpallûʾ wĕḥeṣrôn wĕḵarmî</strong>. These four names reappear in the wilderness census (Num 26:5-7) confirming the genealogical record's consistency across the Pentateuch. The brevity of the listing — just names, no comments — follows the standard ANE genealogical register format: the name is the data; additional biographical information is not the genre's purpose.</p>""",
    "10": """<p><strong>ûḇen-hayyĕmînî</strong> — "and Benjamin." Wait — this verse is Simeon's sons. <strong>wĕšāʾûl ben-hakkĕnaʿănît</strong> — "Shaul the son of a Canaanite woman." The specification of Shaul's Canaanite mother is the only ethnic marker in this genealogy for a mother — it may reflect the mixed-heritage situation of the Simeonite line and is possibly related to the Shechem episode of ch34, where Simeon played a leading role in the violence against a Canaanite city. The ethnic note distinguishes this son within the Simeonite family.</p>""",
    "11": """<p>The sons of Levi: <strong>Gēršôn qĕhāt ûmĕrārî</strong> — the three Levitical families that will structure the entire wilderness Tabernacle service and later Temple service. The Kohathites carry the ark and most sacred furniture (Num 3:31; 4:4-20); the Gershonites carry the tent-coverings (Num 3:25-26; 4:21-28); the Merarites carry the frames (Num 3:36-37; 4:29-33). The three names here are simultaneously genealogical data and the structural foundation of Israel's future worship system.</p>""",
    "12": """<p><strong>wayĕhî ʿēr wĕʾônān bĕʾereṣ kĕnaʿan</strong> — "Er and Onan had died in the land of Canaan." The parenthetical note (also signaled by the waw-disjunctive + imperfect construction) refers back to ch38; the deaths of Er and Onan are included in the genealogy's count even though they did not go to Egypt. <strong>Ḥeṣrôn wĕḥāmûl</strong> — Perez's sons are included even though they were born very close to this time (or possibly after); the genealogy's counting may include anticipated descendants as well as those alive at the moment of departure.</p>""",
    "13": """<p>The sons of Issachar — <strong>tôlāʿ ûpûwwāh wĕyôḇ wĕšimrôn</strong>. The name Puah (<em>Pûwāh</em>) appears later as one of the Hebrew midwives in Egypt (Exod 1:15: <em>Pûʿāh</em>) — a possible connection, though the different spellings may indicate different persons. The Issachar genealogy is otherwise unremarkable in its literary form; its function is numerical (contributing to the 70 count) and genealogical (establishing the tribal lineage).</p>""",
    "14": """<p>The sons of Zebulun — <strong>sereḏ wĕʾēlôn wĕyaḥlĕʾēl</strong>. These three names do not appear prominently in later biblical narrative, consistent with Zebulun's relatively minor role in the tribal history compared to Judah, Ephraim, or Levi. The genealogy's consistent three-to-seven sons per tribe reflects historical memory of the tribal sub-clan structure rather than invented roundness.</p>""",
    "15": """<p><strong>šĕlōšîm wĕšālōš</strong> — "thirty-three in all" for Leah's line. The counting formula for each matriarchal group — "these were [the mother's] children... [number] in all" — structures the genealogy in four maternal blocs: Leah (v15), Zilpah (v18), Rachel (v22), Bilhah (v25). The four-mother structure mirrors the narrative of the preceding chapters and makes explicit the covenant-family's organizational principle: the four women, their sons, and their descendants.</p>""",
    "16": """<p>The sons of Gad — seven names (<strong>ṣipyôn wĕḥaggî šûnî wĕʾeṣbôn ʿĕrî wĕʾărōḏî wĕʾarʾēlî</strong>). Gad's seven sons give a relatively large sub-clan. The numbers vary across the genealogical lists (Gad's sons in Num 26:15-18 have six names with different spellings), reflecting the usual ANE genealogical variation across independent genealogical registers. The variant spellings are not errors but different transliterations or tribal nicknames.</p>""",
    "17": """<p><strong>wûḇĕnôtêhem śerāḥ</strong> — "their sister was Serah." The naming of a daughter is exceptional in this male-dominated genealogy; Serah appears again in Num 26:46 (also exceptional: a named daughter in a census) and in the tradition is associated with extraordinary longevity (some rabbinic traditions make her the one who informed Jacob that Joseph was alive, 45:26). The listing of a named daughter indicates she was remembered as genealogically significant — perhaps as the originator of a recognizable Asherite sub-clan through her descendants.</p>""",
    "18": """<p><strong>šiššāh ʿāśār</strong> — "sixteen in all" for Zilpah's line. The closing parenthetical "(these were the children born to Jacob by Zilpah, whom Laban had given to his daughter Leah)" establishes the maternal identity for the counting section. The passive participial <em>yĕlāḏāh</em> (who was born) applies to Zilpah: "whom Laban had given" (<em>ʾăšer nātan lāḇān lĕlēʾāh bittô</em>). The reminder of Laban's gift of Zilpah frames Zilpah's children within the complicated Laban-household narrative of chs 29-31.</p>""",
    "19": """<p><strong>ûḇĕnê rāḥēl ʾēšet yaʿăqōḇ</strong> — "the sons of Jacob's wife Rachel" — Rachel is specifically designated "Jacob's wife" (<em>ʾēšet yaʿăqōḇ</em>), whereas Leah is simply listed without this honorific earlier (v15). The distinction may reflect the narrator's acknowledgment of Rachel's primacy in Jacob's affection (29:30: "Jacob loved Rachel more than Leah"), or it may be the genealogy's convention for distinguishing the primary wife from the secondary concubines (Zilpah, Bilhah).</p>""",
    "20": """<p><strong>ʾăšer yāllĕḏāh-lô ʾāsĕnat bat-pôṭîperaʿ kōhēn ʾôn</strong> — the full parenthetical identification of Asenath: "daughter of Potiphera, priest of On." The specification of her priestly Egyptian lineage — On (= Heliopolis, the great sun-temple city of Egypt) — locates Ephraim and Manasseh as the grandsons of an Egyptian priest. This mixed heritage does not prevent their full adoption into Israel's tribal structure (48:5); their covenant status is determined by Jacob's blessing-adoption, not by maternal ethnicity.</p>""",
    "21": """<p>The sons of Benjamin — ten names. Benjamin's ten sons are remarkable in number (no other patriarch has ten sons listed here); the ten are the sub-clans of Benjamin. The number varies in different biblical genealogies (1 Chr 8:1-5 gives five sons for Benjamin; Num 26:38-41 gives five differently named sons), reflecting independent genealogical traditions for the Benjaminite tribal history. The ten-son count here gives Benjamin the largest immediate family, which is consistent with the extra attention Jacob pays to Benjamin (chs 42-45).</p>""",
    "22": """<p><strong>ʾarbaʿāh ʿāśār</strong> — "fourteen in all" for Rachel's line. The fourteen includes Joseph himself, Benjamin, and their sons (Joseph's two sons Ephraim and Manasseh are counted in v20, and Benjamin's ten sons are counted in v21 — together 14 from Rachel's line). The Rachel-group count is computed differently from the Leah-group: Rachel's sons and their sons are all direct descendants counted together.</p>""",
    "23": """<p><strong>ûḇen-dān ḥûšîm</strong> — "the son of Dan: Hushim." Dan has only one son listed here, consistent with the historical smallness of the Danite clan (Num 26:42-43 lists one Danite clan, Shuham). The singular son is linguistically significant: the only case in this genealogy of a singular son for a patriarch; the use of <em>ben</em> (singular) versus <em>bĕnê</em> (plural sons) in the other listings marks Dan's demographic situation. The Danites will later become one of the larger tribes by the wilderness census (Num 1:39: 62,700 — second only to Judah).</p>""",
    "24": """<p>The sons of Naphtali — <strong>yaḥṣĕʾēl wĕgûnî wĕyēṣer wĕšillēm</strong> — four sons. Naphtali's four sub-clans appear in Num 26:48-50 with parallel names (Jahzeel/Jahziel, Guni, Jezer, Shillem/Shallum). The consistency across the census lists (Num 26) and this patriarchal register indicates a shared genealogical tradition, however independently transmitted. The Naphtali names include several theophoric elements: <em>ʾēl</em> in Jahzeel, <em>yāh</em> in Jezer (possibly).</p>""",
    "25": """<p><strong>šiḇʿāh</strong> — "seven in all" for Bilhah's line (Dan's one + Naphtali's four + their sons = seven; or the seven listed in vv23-25). The closing parenthetical for Bilhah mirrors the Zilpah-parenthetical of v18: the secondary wives' children are bracketed explicitly as "born to Jacob by [wife], whom Laban had given to [his daughter]." The repetition of Laban's role in providing both secondary wives frames their children within the larger story of Jacob's complex family-formation in Paddan-Aram.</p>""",
    "26": """<p><strong>yōṣĕʾê yĕrēḵô</strong> — "those who came out from his loins/thigh" — the idiom for biological descent. <em>Yārēk</em> (thigh/loin) is the euphemism for the procreative organ; the same body-part appears in the oath-gesture (24:2,9; 47:29: "put your hand under my thigh"). The count of 66 (<em>šiššîm wĕšēš</em>) excludes Joseph (already in Egypt) and his two sons — only direct descendants who made the journey. The distinction between 66 (those who went) and 70 (the full family count) is clarified in the next verse.</p>""",
    "27": """<p><strong>šiḇʿîm</strong> — "seventy in all." The MT count of 70 (66 + Joseph + Ephraim + Manasseh = 69; Jacob himself makes 70 — or the two sons of Joseph + Joseph = 3 added to 66 + 1 = 70 with Jacob). The LXX counts 75, following a different calculation that adds five more descendants of Joseph (cited in Acts 7:14; Stephen uses the LXX). Deut 10:22 gives 70 (agreeing with the MT here). The discrepancy is a known manuscript/counting-tradition difference; the number 70 is symbolically complete (70 nations of the earth in Gen 10; 70 elders of Israel in Exod 24:1; Num 11:16).</p>""",
    "28": """<p><strong>lĕhôrōt lĕpānāyw</strong> — "to direct/show the way" before him. The verb <em>yārāh</em> (Hiphil: to direct, teach, point the way — also the root of <em>tôrāh</em>, instruction/law) is used for Judah's advance-scouting mission. Judah is sent ahead "to teach/direct" the way to Goshen — the same Judah who was the spokesman for the brothers before Joseph (44:14-34) and who offered himself as a surety for Benjamin (44:33). Judah's leadership role in these final chapters anticipates the Judah-tribe's covenant-leadership role in later Israel.</p>""",
    "29": """<p><strong>wayyipōl ʿal-ṣawwĕʾrāyw</strong> — "he fell upon his neck" — the most intimate physical embrace in the OT idiom: falling on the neck (throwing one's arms around the other's neck) is the full-bodied embrace of intense emotional reunion (also 45:14: Joseph embracing Benjamin; 45:15: embracing his brothers). <strong>wayyēḇk ʿōd</strong> — "and wept still/again" (<em>ʿôd</em>, yet/still/again) — the adverb indicates that Joseph wept at length, possibly in addition to previous weeping (45:2,14-15). The reunion weeping is the most sustained of Joseph's repeated weepings.</p>""",
    "30": """<p><strong>ʾāmûtāh happaʿam</strong> — "let me die this time" — the cohortative form of <em>māwet</em> (to die), expressing resigned readiness or willingness: "I can die now / let me now die." The cohortative is the mode of volition — Jacob is not expressing despair but completion: having seen Joseph, his life's deepest longing is fulfilled. Simeon uses the same formula in reverse at 43:14 (<em>kǎʾăšer šāḵaltî šākāltî</em>); Jacob uses it here as a statement of contentedness with whatever comes next.</p>""",
    "31": """<p><strong>ʾeʿĕleh wĕʾaggîḏāh lĕparʿōh</strong> — "I will go up and tell Pharaoh" — Joseph's announcement uses <em>ʿālāh</em> (go up) for the journey to Pharaoh's court, consistent with the Egyptian social geography where the court was "above" in terms of social status (even if the Nile flows north/downward). The phrase "who were living in Canaan" (<em>hayyōšĕḇîm bĕʾereṣ kĕnaʿan</em>) frames the family's prior location for Pharaoh's information; the past tense ("were living") signals the permanent character of the move.</p>""",
    "32": """<p><strong>ʾanšê miqneh hāyû</strong> — "the men are men of livestock" (literally "men of cattle/stock they have been"). The Qal perfect <em>hāyû</em> expresses their established identity: this is what they have always been. <strong>ûḇĕʿîrām ûḇĕqārām ûḵol-ʾăšer lāhem hēḇîʾû</strong> — "and their flocks and herds and everything they own they have brought" — the inventory of what the family has brought signals both their pastoral identity and their economic status as a self-sufficient pastoral household, not refugees seeking charity.</p>""",
    "33": """<p><strong>mah-miʿăśêkem</strong> — "what is your occupation?" — the expected Pharaonic interrogation. Joseph's coaching (vv33-34) prepares the brothers for the formal court protocol: they should anticipate this question and answer it correctly. The conditional "when Pharaoh calls you in" (<em>wĕhāyāh kî-yiqrāʾ lākem parʿōh</em>) is the waw-consecutive + verb of condition, structuring the anticipated event as a foreseeable future that can be prepared for.</p>""",
    "34": """<p><strong>tôʿăḇat miṣrayim</strong> — "detestable to the Egyptians" — <em>tôʿēḇāh</em> is the strongest term for ritual/moral abomination in Hebrew; the same word used for idolatry (Deut 7:25-26), sexual violations (Lev 18:22-30), and the practices that made the Canaanites lose their land (Lev 18:27-28). Its application to shepherds in the Egyptian context may reflect the cultural memory of the Hyksos (the "shepherd kings" who ruled Egypt 1650-1550 BCE and left a traumatic xenophobic legacy), though this identification is debated. The motive is clear: the Egyptians' aversion to shepherds will ensure the Israelites are settled in Goshen (a frontier region) rather than integrated into Egyptian society — a providential separation.</p>"""
  },
  "47": {
    "1": """<p><strong>wayyāḇōʾ yôsēp wayyaggēḏ lĕparʿōh</strong> — Joseph comes and tells Pharaoh; the sequential waw-consecutives narrate Joseph's court appearance. The report to Pharaoh uses the same cattle-inventory formula as Joseph's coaching (46:32): "flocks and herds and everything they have" (<em>ṣōʾnām ûḇĕqārām wĕḵol-ʾăšer lāhem</em>). The verbal parallel between the coaching (46:32) and the report (47:1) shows the brothers followed Joseph's instruction exactly — a small narrative confirmation that the plan was executed as planned.</p>""",
    "2": """<p><strong>ûmiqqĕṣēh ʾeḥāyw</strong> — "from the extremity/end of his brothers" — the five selected are chosen from the extremity (<em>qāṣeh</em>) of the brothers. The phrase is ambiguous: "from the extremes" could mean the oldest and youngest, or the least distinguished, or a representative sampling. The LXX adds "five men," consistent with the MT. The selection of five (half of ten brothers) for the Pharaonic presentation was probably a practical judgment — presenting all ten at once would be unwieldy, while five represents the family adequately.</p>""",
    "3": """<p><strong>rōʿê ṣōʾn ʿăḇādêkā</strong> — "shepherds of flocks are your servants" — the brothers' self-designation as "your servants" (<em>ʿăḇādêkā</em>) is the standard court-protocol of address to the king; it implies subordination and request. "Just as our fathers were (<em>gam-ʾăḇōtênû</em>)" — the "also our fathers" adds the hereditary dimension: this is not a new trade adopted under pressure but a generational identity. The echo of Joseph's coaching (46:34: "your servants have tended livestock from our boyhood, just as our fathers did") shows the brothers followed the prepared script faithfully.</p>""",
    "4": """<p><strong>lāgûr bāʾāreṣ bāʾnû</strong> — "we have come to sojourn (<em>gûr</em>) in the land." The verb <em>gûr</em> (to sojourn as a resident alien, without full land rights) is the key term of the patriarchal gēr identity (Abram as gēr, 12:10; 17:8; 20:1; Isaac at Gerar, 26:3; the Egyptian oppression described as Israel's gēr status, Deut 26:5). The brothers' self-identification as <em>gērîm</em> before Pharaoh is simultaneously a legal request (give us sojourner status) and a narrative echo of the entire patriarchal covenant-journey. <strong>kî-kāḇēḏ hārāʿāḇ</strong> — "because the famine is severe" — the causal clause justifies the sojourn request.</p>""",
    "5": """<p><strong>ʾaḇîkā wĕʾaḥêkā bāʾû ʾēlêkā</strong> — Pharaoh's acknowledgment: "your father and your brothers have come to you" — the possessive forms (<em>ʾaḇîkā, ʾaḥêkā</em>, your father, your brothers) frame the family as Joseph's family in Pharaoh's speech; Pharaoh recognizes the family through Joseph. The grammatical point: Pharaoh speaks of the family as Joseph's (<em>ʾēlêkā</em>, to you), not as subjects of his own — the covenant-family retains its own identity even in Egypt under Pharaoh's patronage.</p>""",
    "6": """<p><strong>ʾereṣ miṣrayim lĕpānêkā hîʾ</strong> — "the land of Egypt is before you" — the same "before you" (lĕpānêkā) formula of ch13 (YHWH to Abram: "all the land that you see I will give to you"). Pharaoh mirrors the covenant-formula without knowing it; the "best of the land" (<em>bĕmêṭaḇ hāʾāreṣ</em>) offered to Jacob's family echoes the "best part of the land" that Joseph gave them (v11). <strong>wĕyēšĕḇû bĕʾereṣ gōšen</strong> — the settlement in Goshen fulfills Joseph's strategy (46:34: the shepherd-abomination ensures Goshen placement).</p>""",
    "7": """<p><strong>waybāreḵ yaʿăqōḇ ʾet-parʿōh</strong> — "Jacob blessed Pharaoh." The verb <em>bārak</em> (Piel: to bless) with Jacob as subject and Pharaoh as object is the narrative's most politically charged moment. In ANE convention, a person with superior access to divine favor could bless one of lesser standing; Jacob, as the covenant-patriarch, carries YHWH's blessing-capacity established in 12:2-3. The blessing of Pharaoh by the immigrant patriarch echoes the covenant's promise that "all nations will be blessed through you" (12:3) — beginning with the world's most powerful king.</p>""",
    "8": """<p><strong>kamāh yĕmê šĕnê ḥayyêkā</strong> — "How many are the days of the years of your life?" Pharaoh's question uses the triple accumulation — days (<em>yāmîm</em>) + years (<em>šānîm</em>) + life (<em>ḥayyîm</em>) — which is the most expansive formula for a person's age. The question is not merely polite inquiry but a recognition of Jacob's evident antiquity; the old patriarch arriving from Canaan presented an image of extreme age even in a culture that respected age highly.</p>""",
    "9": """<p><strong>šĕnê mĕgûrāy</strong> — "the years of my sojourning/pilgrimage." The noun <em>mĕgûr</em> (from <em>gûr</em>, to sojourn) means the period of one's sojourning as an alien — it is both a temporal and a status word. Jacob's self-description as "sojourning" (not "living" or "dwelling") defines his entire life as a pilgrimage without a permanent home. <strong>mĕʿaṭ wĕrāʿîm</strong> — "few and evil/difficult." <em>Rāʿ</em> (bad/evil/distressing) applied to Jacob's years is the same adjective used for the "bad years" of famine (41:27). The contrast with "the pilgrimage of my fathers" (<em>mĕgûrê ʾăḇōtāy</em>) acknowledges Abraham (175) and Isaac (180) as models of longer covenant-lives.</p>""",
    "10": """<p><strong>waybāreḵ yaʿăqōḇ ʾet-parʿōh</strong> — Jacob blesses Pharaoh a second time upon leaving (forming a bracket: he blessed Pharaoh upon arrival, v7, and again upon departure, v10). The double blessing is the liturgical frame of the encounter: the blessing is not merely a convention but the covenant-patriarch's formal transmission of divine favor to the pagan ruler. The departure-blessing is distinct from the arrival-blessing — the arrival-blessing is a greeting; the departure-blessing is a benediction, a sending-away with divine benefit.</p>""",
    "11": """<p><strong>bĕʾereṣ rameśēs</strong> — "in the land of Rameses." This anachronistic place-name (the city Rameses was built by Israelite labor in Exod 1:11) uses the later name known to the audience rather than the Bronze Age name of the Goshen-district. The geographic identification locates Goshen within the territory of the later Rameses administrative district in the eastern Nile delta — consistent with archaeological evidence for Israelite presence in the eastern delta during the New Kingdom period.</p>""",
    "12": """<p><strong>lĕpî haṭṭap</strong> — "according to the number of their children/little ones" — <em>ṭap</em> refers specifically to the youngest children in a household; the phrase "by the mouth of the little ones" means food was apportioned based on how many children each family unit had to feed. The attention to children in the provision-formula reflects the covenant-people's demographic priority — the multiplication of Jacob's family in Egypt (47:27: "they were fruitful and increased greatly") requires adequate provision for the youngest generation.</p>""",
    "13": """<p><strong>lēḥem ʾên bĕḵol-hāʾāreṣ</strong> — "there was no bread/food in all the land" — the starkness of the famine is restated after the settlement of Jacob's family; the narrative refocuses on the larger economic crisis that Joseph must manage. The conjunction <strong>kî-kāḇēḏ hārāʿāḇ mĕʾōḏ</strong> — "because the famine was very severe" — uses the same <em>kāḇēḏ</em> (heavy) vocabulary applied earlier to the famine (41:31: "very severe") and to Pharaoh's hardened heart (Exod 7:14: "Pharaoh's heart is hardened").</p>""",
    "14": """<p><strong>wayyiqabbēṣ yôsēp ʾet-kol-hakkesep</strong> — Joseph "gathered/collected" (<em>qibbēṣ</em>, Piel intensive) all the money. The Piel of <em>qāḇaṣ</em> is the intensive collecting-together form — a comprehensive, thorough gathering rather than a casual accumulation. <strong>wayyāḇēʾ ʾet-hakkesep bêtāh parʿōh</strong> — "he brought the silver to Pharaoh's house/palace." The systematic centralization of all monetary wealth in Egypt and Canaan to Pharaoh's treasury through the grain-sale is the economic dimension of Joseph's administration.</p>""",
    "15": """<p><strong>lāmmāh nāmût negdekā</strong> — "why should we die before your eyes (<em>nĕgdĕkā</em>)?" — the appeal "before your eyes" is the covenant-loyalty formula inverted: the Egyptians appeal to Joseph's presence and authority as their reason not to die. <strong>kî ʾāpas hakkāsep</strong> — "because the silver has run out" (<em>ʾāpas</em>, to come to an end/be exhausted — a poetic and strong verb for the complete depletion of resources). The transition from money-purchase to barter is the narrative's marker of economic desperation deepening.</p>""",
    "16": """<p><strong>hāḇû miqnêkem</strong> — "give/bring your livestock" — the imperative <em>hāḇû</em> (from <em>yāḇ</em> or <em>nātan</em>: give!) is a strong command-form. The exchange structure shifts: first currency (v14), then livestock (vv16-17), then land and persons (vv19-20). The progressive stages of asset-transfer chart the famine's systematic economic devastation of Egypt. <strong>ûʾettnāh lākem bĕmiqnêkem</strong> — "and I will give to you for your livestock" — the exchange principle remains consistent: value given for value received.</p>""",
    "17": """<p><strong>bassûsîm ûḇĕmiqnēh haṣṣōʾn ûḇĕmiqnēh habbāqār</strong> — "horses, sheep and goats, cattle" — the inventory of livestock exchanged for grain lists the primary categories of ANE pastoral wealth: horses (prestige animals, also military assets), sheep/goats (flock animals, the most common pastoral wealth), cattle (draft and meat animals). <strong>waynĕhălem baśśānāh hahîʾ</strong> — "he brought them through (<em>nāhal</em>, to guide/lead) that year" — the Piel of <em>nāhal</em> is the shepherd's leading-to-water idiom (Ps 23:2: "he leads me beside still waters"), here applied to Joseph's economic leadership of Egypt through the famine year.</p>""",
    "18": """<p><strong>lōʾ-nĕkahēḏ mēʾăḏōnî</strong> — "we cannot hide (<em>kāḥaḏ</em>) from my lord" — the Niphal of <em>kāḥaḏ</em> (to hide/conceal) expresses the Egyptians' transparency in admitting complete destitution. The "we cannot hide" formula is a confession of total dependence. <strong>kî ʾim-gĕwiyyātēnû wĕʾadmātēnû</strong> — "except our bodies and our land" — <em>gĕwiyyāh</em> (body, frame, physical person — also used for the body of the ark in Ezek 1:11) represents the only assets remaining after money and livestock are gone.</p>""",
    "19": """<p><strong>qĕnēh ʾōtānû wĕʾet-ʾadmātēnû baléḥem</strong> — "buy us and our land for bread" — the Egyptians' proposal to sell themselves and their land is the final stage of the asset-transfer. <strong>wĕnihyeh ʾănaḥnû wĕʾadmātēnû ʿăḇāḏîm lĕparʿōh</strong> — "and we with our land will be servants to Pharaoh" — the verb <em>hāyāh</em> (be) in the cohortative (<em>nĕhyeh</em>) expresses the people's willing self-offering: "let us be servants." The economic enserfment of Egypt (distinct from Israel's later compelled slavery) is the result of the famine; the Israelites in Goshen are explicitly protected from this process (v27).</p>""",
    "20": """<p><strong>wayyiqen yôsēp ʾet-kol-ʾadmat miṣrayim lĕparʿōh</strong> — Joseph "acquired/bought" (<em>qānāh</em>, the same verb as "Creator/Possessor of heaven and earth" in Gen 14:19) all the land of Egypt for Pharaoh. The land-purchase by the state is the economic climax: all private landholding (except the priests', v22) is absorbed by Pharaoh. <strong>kî-ḥāzaq ʿălêhem hārāʿāḇ</strong> — "because the famine was too severe for them" (<em>ḥāzaq</em>, to be strong/pressing — the same word for the hardening of Pharaoh's heart in Exodus).</p>""",
    "21": """<p><strong>wĕʾet-hāʿām heʿĕḇîr ʾōtô lĕʿārîm</strong> — "and the people he moved to cities" (or: "he reduced the people to servitude"). The Hebrew text is ambiguous: <em>heʿĕḇîr</em> (Hiphil of <em>ʿāḇar</em>, to cause to pass/move) can mean "he moved them" (geographically, from country to cities for food distribution) or, with a different reading, "he enslaved them." The Samaritan Pentateuch and LXX read differently; most modern translations follow the MT's "moved to cities" — consistent with the food-distribution logistics of a centralized famine-response.</p>""",
    "22": """<p><strong>raq ʾadmat hakkōhănîm lōʾ qānāh</strong> — "only the land of the priests he did not buy." The exemption of priestly land is consistent with Egyptian practice: temple estates were traditionally exempt from royal taxation and appropriation in Egypt. The reason given — <strong>kî ḥōq lakkōhănîm mēʾēt parʿōh</strong> — "because there was a fixed allotment for the priests from Pharaoh" (<em>ḥōq</em>, statute/fixed portion — the same word as the legal statute in v26 and as the Mosaic "statutes" of the law). The Egyptian priestly class had a separate supply-chain from the royal granaries.</p>""",
    "23": """<p><strong>hinnēh qānîtî ʾetkem hayyôm wĕʾet-ʾadmatkĕm lĕparʿōh</strong> — "now I have bought you and your land today for Pharaoh." The <em>hinnēh</em> (behold) draws attention to the formal declaration of the economic transaction; the perfect tense (<em>qānîtî</em>, I have acquired) marks the completed action. <strong>hēʾ-lākem zera</strong> — "here is seed for you" — the provision of seed following the acquisition establishes the sharecropping arrangement: the land belongs to Pharaoh; the people will work it; the harvest is divided.</p>""",
    "24": """<p><strong>ûhāyāh baṭṭĕḇûʾōt ûnĕtattem ḥămîšît lĕparʿōh</strong> — "and when the harvest comes in, give a fifth (<em>ḥōmeš</em>) to Pharaoh." The <em>ḥōmeš</em> (fifth, 20%) is the tax rate established as Joseph's land-policy. The remaining four-fifths remain with the farmers for seed, food, and household needs. The 20% agricultural tax is consistent with known ANE administrative practices (Mesopotamian temple-estate taxation often ran 10-20%); the Egyptian system formalized here runs as a law "still in force today" (v26), embedding the Josephine policy in Egyptian agricultural history.</p>""",
    "25": """<p><strong>hĕḥĕyîtānû</strong> — "you have saved our lives" — the Hiphil perfect of <em>ḥāyāh</em> (to live/cause to live): Joseph "caused us to live." The same verb-form appears in the Rahab narrative (Josh 2:13: "you will spare our lives"), the widow of Zarephath (1 Kgs 17:13: "make food for me first"), and throughout the Joseph cycle (45:7: "to preserve a remnant on earth"). <strong>nimṣāʾ-ḥēn bĕʿênê ʾăḏōnî</strong> — "may we find favor (<em>ḥēn</em>) in the eyes of my lord" — the grace-formula of patron-client relationship.</p>""",
    "26": """<p><strong>wayyāśem ʾōtāh yôsēp lĕḥōq</strong> — "Joseph established it as a statute (<em>ḥōq</em>)." The word <em>ḥōq</em> (fixed ordinance/statute) is the same term used for Pharaoh's allotment to the priests (v22) and the Mosaic law-statutes (<em>ḥuqqôt</em>). The "law (<em>ḥōq</em>) concerning land... still in force today" — the narrative note grounds the Josephine tax policy in the reader's present: a known Egyptian agricultural practice is traced to Joseph's administration. <strong>ʿaḏ hayyôm hazzeh</strong> — "until this day/to this day" is the standard formula for an etiology whose effect persists into the narrator's own time.</p>""",
    "27": """<p><strong>wayyiprû wayyirbu mĕʾōḏ</strong> — "they were fruitful and increased greatly" — the creation-blessing formula (<em>pārāh ûrāḇāh</em>, be fruitful and multiply) of Gen 1:28, applied to the covenant-people multiplying in Egypt. The same formula will open Exodus (Exod 1:7: "the Israelites were exceedingly fruitful; they multiplied greatly"), connecting the Goshen-flourishing of Genesis 47 to the Egypt-multiplication crisis of Exodus 1. The covenant-promise of innumerable offspring (13:16; 15:5) is being fulfilled in Egypt — precisely through the famine that drove them there.</p>""",
    "28": """<p><strong>šĕḇaʿ ʿeśrēh šānāh</strong> — "seventeen years" in Egypt — Jacob entered Egypt at 130 (v9) and died at 147. The seventeen years mirrors the number of years Joseph spent in Jacob's household before the brothers sold him: Joseph was 17 when sold (37:2), seventeen years with his father; Jacob lived seventeen years with Joseph in Egypt. The numerical mirror (17 + 17) is a deliberate structural balance in the Joseph narrative's architecture.</p>""",
    "29": """<p><strong>śîm-nāʾ yāḏĕkā taḥat yĕrēkî</strong> — "put your hand under my thigh" — the oath-by-thigh gesture (also 24:2,9: Abraham's servant's oath to find Isaac's wife). The <em>yārēk</em> (thigh/loin) oath places the sworn commitment in proximity to the procreative seat of the family's continuity: swearing by the loins is swearing by everything the future holds. <strong>ḥesed weʾĕmet</strong> — the covenant word-pair of loyal-love (<em>ḥesed</em>) and faithfulness/truth (<em>ʾĕmet</em>), appearing together as the summary of covenant-loyalty (Exod 34:6; Ps 86:15; Prov 3:3; John 1:14: "full of grace and truth").</p>""",
    "30": """<p><strong>wĕšāḵaḇtî ʿim-ʾăḇōtāy</strong> — "when I rest with my fathers" — the <em>šākaḇ ʿim ʾăḇōtāyw</em> (lie down with one's fathers) idiom is the standard OT death-formula (used throughout Kings and Chronicles for royal deaths). <strong>ûnĕśāʾtanî miṣrayim</strong> — "carry me up from Egypt" — the Qal of <em>nāśāʾ</em> (to lift/carry/bear) — the same verb for bearing the Ark (Num 4:15,19-20) and for the cloud bearing Israel (Isa 63:9). Jacob's body is to be borne back like the covenant-object it is, returning to the land of promise where the covenant-dead belong.</p>""",
    "31": """<p><strong>wayyištaḥû yiśrāʾēl ʿal-rōʾš hammiṭṭāh</strong> — "Israel worshiped leaning on the top of his <em>miṭṭāh</em>." The consonantal Hebrew <em>מטה</em> is ambiguous: voweled as <em>miṭṭāh</em> (bed, MT), or as <em>maṭṭēh</em> (staff/rod, as the LXX reads: <em>ἐπὶ τὸ ἄκρον τῆς ῥάβδου αὐτοῦ</em>). The LXX/Heb 11:21 reading (staff) has Jacob worshiping as he leans on his pilgrim's staff — a powerful image of faith in extremis. The MT reading (bed) has him leaning on the headboard of his deathbed as he bows in worship. The two readings represent different vowel-pointing traditions of the same consonants; Heb 11:21 cites the LXX version as Jacob's act of faith at the end of his life.</p>"""
  },
  "48": {
    "1": """<p><strong>ʾăšer-ḥoleh ʾāḇîkā</strong> — "your father is ill" — the <em>ḥālāh</em> (Qal participle, to be sick/weak) signals the deathbed context. Joseph takes both sons (<em>Mĕnaššeh wĕʾeprāyim</em>) — the positioning of Manasseh before Ephraim in v1 (and again in v13's setup) reflects birth-order expectation; the narrative's reversal of this order in vv14,19-20 is the chapter's theological point. The chapter's drama is structured around the expected eldest-first priority and Jacob's deliberate subversion of it.</p>""",
    "2": """<p><strong>wayyithazzēq yiśrāʾēl wayyēšeḇ ʿal-hammiṭṭāh</strong> — "Israel rallied his strength (<em>hithazzēq</em>, Hithpael: strengthened himself / mustered strength) and sat up on the bed." The Hithpael of <em>ḥāzaq</em> (to be strong) is the reflexive of self-rallying — the same form used for David's self-strengthening (1 Sam 30:6: "David strengthened himself in the LORD his God"). Jacob's rallying of strength at the approach of death for this final blessing is the ultimate covenant-act: he collects himself for one last formal transmission of the covenant-identity.</p>""",
    "3": """<p><strong>ʾĒl Šadday nirʾāh ʾēlay bĕlûz</strong> — "God Almighty appeared to me at Luz." The divine name <em>ʾĒl Šadday</em> (17:1) is the patriarchal covenant-name; Jacob cites the Bethel/Luz appearance (35:11: "I am God Almighty — be fruitful and increase in number") as the covenant-event being recalled and applied to the Ephraim-Manasseh blessing. The perfect tense <em>nirʾāh</em> (appeared to me — Niphal of <em>rāʾāh</em>) is the standard theophanic appearance verb; by citing the past theophany, Jacob grounds the current blessing in divine commission.</p>""",
    "4": """<p><strong>qĕhal ʿammîm</strong> — "a community/assembly of peoples" — <em>qāhāl</em> (assembly, congregation) combined with <em>ʿammîm</em> (peoples) creates the covenant formula "assembly of peoples." The same <em>qāhāl</em> will be the word for the Mosaic assembly at Sinai (Deut 9:10; 10:4; 18:16) and for the gathered congregation of Israel. <strong>mōrāšāh lĕzarʿăkā</strong> — "as an everlasting possession (<em>mōrāšāh</em>) to your descendants" — <em>mōrāšāh</em> (possession, inheritance) is the covenant-land word used in Ezek 36:12 and elsewhere for Israel's covenant inheritance; here applied to the Canaan promise in its original Bethel formulation.</p>""",
    "5": """<p><strong>lî-hēm</strong> — "they are mine" — the adoption formula. Jacob adopts Ephraim and Manasseh as his own sons, giving Joseph effectively a double-share of the inheritance (two tribal allotments instead of one). The comparison "just as Reuben and Simeon are mine (<em>kĕrĕʾûḇēn wĕšimʿôn yihyû-lî</em>)" uses the firstborn and second-born as the reference point — Ephraim and Manasseh will be reckoned at the same tribal-leadership level as the eldest sons of Jacob. This is the legal basis for the Josephic tribes (the two half-tribes of Ephraim and Manasseh) replacing the tribe of Joseph in the conquest-era tribal structure.</p>""",
    "6": """<p><strong>ʾaḥărê tôlĕḏōtām lĕkā yihyû</strong> — "they will be yours" — any sons born to Joseph after Ephraim and Manasseh will not receive independent tribal status; they will be "reckoned under the names of their brothers" (<em>ʿal-šēm ʾăḥêhem yiqqārĕʾû bĕnaḥălātām</em>). The <em>yiqqārĕʾû</em> (Niphal: will be called) is the covenant-naming verb — to be "called by the name" of someone is to belong to their household and inheritance. The arrangement limits the tribal multiplication from Joseph to exactly two (Ephraim and Manasseh); further sons of Joseph are absorbed into these two tribal territories.</p>""",
    "7": """<p><strong>kiḇrat-ʾereṣ</strong> — "a little distance/short way" — <em>kiḇrāh</em> is a hapax legomenon (unique occurrence) in the sense of a distance measure; it appears only here and in Gen 35:16, both describing Rachel's burial location. The word may derive from <em>kāḇar</em> (to be many/much) suggesting "some distance" rather than a precise measurement. The parenthetical on Rachel's death (<em>māṯāh ʿālay rāḥēl</em>, "Rachel died upon me" — the unusual prepositional "upon me" expressing Jacob's personal grief) is Jacob's final remembered grief, cited here as explanation for why he buries her in Canaan rather than at Machpelah.</p>""",
    "8": """<p><strong>mî-ʾēlleh</strong> — "who are these?" — the question of the nearly-blind patriarch. Jacob's failing sight (v10: <em>kāḇĕḏû ʿênê yiśrāʾēl mizzōqen</em>, "Israel's eyes were heavy from old age" — <em>kāḇēḏ</em>, to be weighty/heavy, the glory-word applied to dimming vision) means he cannot see clearly who has entered. The question is not ignorance of their identity but an invitation for Joseph to formally introduce the sons for the blessing ceremony — the formal introduction is required for the legal adoption and blessing.</p>""",
    "9": """<p><strong>bĕnāy hēm ʾăšer-nātan-lî ʾĕlōhîm bāzeh</strong> — "they are my sons that God has given me here" — Joseph's response uses the divine-gift formula (<em>nātan lî ʾĕlōhîm</em>, God gave to me) — the same formula used for Benjamin (43:23) and for children generally in covenant-birth narratives (29:32-35; 30:6,18,20). <strong>qāḥēm-nāʾ ʾēlay wăʾăḇārkēm</strong> — "bring them to me (<em>qāḥ</em>, imperative of <em>lāqaḥ</em>) so I may bless them" — the <em>ʾăḇārkēm</em> (cohortative: may I bless them) expresses Jacob's will and intent rather than prediction.</p>""",
    "10": """<p><strong>kāḇĕḏû ʿênê yiśrāʾēl mizzōqen</strong> — "Israel's eyes were heavy (<em>kāḇēḏ</em>) from old age" — the same <em>kāḇēḏ</em> verb used for Eli's failing sight (1 Sam 4:15) and for the weight/glory of the divine presence. The irony of the man who deceived his own blind father (ch27) now being blind himself at the moment of his great blessing is the narrative's structural echo: what Jacob did to Isaac, Jacob will now experience from within — the patriarch whose deception exploited his father's blindness now blesses while blind, and his crossing of hands is deliberate, not accidental. <strong>wayyiššaq lāhem wayyĕḥabbēq lāhem</strong> — "he kissed them and embraced them."</p>""",
    "11": """<p><strong>rĕʾôt pānêkā lōʾ pilaltî</strong> — "I never expected (<em>lōʾ pilaltî</em>, I did not conceive/think possible — from <em>pālal</em>, to intervene, to judge, to intercede) to see your face again." The verb <em>pālal</em> (Hitpael elsewhere; here Piel) in this context means "to reckon as possible/to anticipate" — a rare use. The divine gift of seeing Joseph again AND Joseph's sons is stated as a double unexpected grace: <strong>wĕhinnēh herʾāh ʾōtî ʾĕlōhîm gam ʾet-zarʿekā</strong> — "and behold God has shown me even your offspring" (<em>gam</em>, "even/also" for the added grace).</p>""",
    "12": """<p><strong>wayyiqqaḏ lĕʾappāyw ʾarṣāh</strong> — "he bowed down with his face to the ground" — Joseph's prostration before his father is the reversal of the dream-bowing where the brothers would bow to Joseph (37:9-10). The covenant-patriarch receives the prostration of the covenant-heir as a sign of the blessing's weight: the son who was bowed to by kings bows before his father for the patriarchal blessing. <strong>ʾet-ʾeprāyim bîmînô mîśĕmōl yiśrāʾēl</strong> — the spatial arrangement sets up the narrative climax of the crossed hands.</p>""",
    "13": """<p><strong>ʾet-ʾeprāyim bîmînô mîśĕmōl yiśrāʾēl wĕʾet-mĕnaššeh biśmōʾlô mîmîn yiśrāʾēl</strong> — "Ephraim on his right toward Israel's left hand, and Manasseh on his left toward Israel's right hand." Joseph positions the sons so that Jacob's right hand (the blessing hand — right hand = authority, power, honor throughout the OT: Ps 16:11; 17:7; 18:35; 110:1) will land on the elder Manasseh. The spatial logic is explicit: Joseph carefully arranges the sons so the expected elder-first blessing will follow automatically from their positions.</p>""",
    "14": """<p><strong>śikel ʾet-yādāyw</strong> — "he crossed (<em>śikel</em>) his hands" — the Piel of <em>śākal</em> (to act wisely/with discernment; to cross, interchange). The Piel <em>śikel</em> combines the meanings: he deliberately, discerningly crossed his hands. The same root <em>śākal</em> means "to succeed/act wisely" in the Hiphil (Josh 1:8; Ps 2:10; Prov 1:3; Isa 52:13: "my servant shall act wisely" — the Servant Song's opening). The blind patriarch's deliberate reversal of expected hand-placement over the sons is an act of wisdom-insight, not fumbling accident — confirmed by his response to Joseph's protest (v19: "I know, my son, I know").</p>""",
    "15": """<p><strong>hāʾĕlōhîm ʾăšer hithallĕkû ʾăḇōtāy lĕpānāyw</strong> — "the God before whom my fathers Abraham and Isaac walked" — the Hithpael of <em>hālak</em> (walk): <em>hithallĕkû</em> is the reflexive-iterative — "they walked back and forth / they walked habitually" in YHWH's presence. The same Hithpael appears in the covenant-command of 17:1 ("walk before me") and in Enoch's walking with God (5:22,24: <em>wayyithallēk ḥănôk ʾet-hāʾĕlōhîm</em>). <strong>hāʾĕlōhîm hārōʿeh ʾōtî</strong> — "the God who has been my shepherd" — the Qal active participle <em>rōʿeh</em> (one who shepherds/pastures) as a divine epithet; this is the first instance of God-as-shepherd in the OT, the paradigm that Ps 23:1 ("The LORD is my shepherd") will expand.</p>""",
    "16": """<p><strong>hammalʾāk haggōʾēl ʾōtî mikol-rāʿ</strong> — "the Angel who has redeemed me from all evil." The participle <em>gōʾēl</em> (one who redeems/acts as kinsman-redeemer) is the first use of the <em>gāʾal</em> root applied to a divine agent. The <em>gōʾēl</em> (kinsman-redeemer) was the family member legally obligated to buy back land sold in poverty, redeem a relative from slavery, and avenge the blood of a murdered relative (Lev 25:25-28; Ruth 3:9,12-13; Num 35:19). The divine malʾāk as <em>gōʾēl</em> applies the kinship-redemption concept to YHWH's rescue of Jacob throughout his life — the covenant-God as the ultimate kinsman-redeemer. Job's confession ("my Redeemer lives," Job 19:25: <em>gōʾălî</em>) draws on the same vocabulary.</p>""",
    "17": """<p><strong>wayyēraʿ bĕʿênāyw</strong> — "it was evil in his eyes" — the idiom for displeasure: <em>rāʿ bĕʿênê</em> (evil in the eyes of) is the standard Hebrew expression for something that displeases or is judged bad (also Gen 21:11: "the matter was evil in Abraham's eyes"). <strong>wayyitmōk yad-ʾāḇîw lĕhāsîr ʾōtāh mēʿal rōʾš ʾeprāyim</strong> — "he took hold of his father's hand to move it from Ephraim's head" — the physical intervention: Joseph tries to correct what he reads as a paternal mistake. The verb <em>tmk</em> (Qal: to grasp/support) is the holding-fast verb; Joseph grips Jacob's hand to redirect it.</p>""",
    "18": """<p><strong>lōʾ-ḵēn ʾāḇî</strong> — "not so, my father" — Joseph's correction uses the direct negative + vocative. <strong>kî-zeh habbĕḵôr śîm yĕmînĕkā ʿal-rōʾšô</strong> — "for this one is the firstborn (<em>bĕḵôr</em>); put your right hand on his head." Joseph appeals to the firstborn-right as the obvious principle governing the blessing's hand-placement. The <em>bĕḵôr</em> (firstborn) right was the legal foundation of inheritance priority throughout the OT (Deut 21:17; the explicit firstborn-blessing legislation). Joseph invokes an unquestionable legal principle — not knowing that his father is not confused but is intentionally reversing it.</p>""",
    "19": """<p><strong>yāḏaʿtî ḇĕnî yāḏaʿtî</strong> — "I know, my son, I know" — the double <em>yāḏaʿtî</em> is the emphatic confirmation: Jacob is fully conscious of what he is doing; this is not old-age confusion. <strong>wĕhûʾ yigdal wĕʾûlām ʾāḥîw haqqāṭōn yigdal mimmennû</strong> — "he also will become great, but his younger brother will be greater than he." The comparative <em>gādôl</em> / <em>yigdal mimmennû</em> (greater from/than him) uses the same verb of greatness applied to Ishmael's promise (17:20) and to the Abrahamic covenant (12:2: "I will make you great"). <strong>ûzarʿô yihyeh mĕlōʾ-haggôyim</strong> — "his descendants will be the fullness of nations" — <em>mĕlōʾ-haggôyim</em> (fullness/complete-number of nations) is unique in this sense in the OT; it anticipates Ephraim's territory becoming the dominant northern-kingdom tribal block.</p>""",
    "20": """<p><strong>bĕkā yĕḇāreḵ yiśrāʾēl</strong> — "by you Israel will bless" — the blessing formula itself becomes the standard blessing-formula for later Israel: "May God make you like Ephraim and Manasseh." The Piel <em>yĕḇāreḵ</em> (will bless) is future — the blessing pronounced now will become the proverbial formula for covenant-blessing in Israel (still used today in Jewish Shabbat blessing of children). <strong>wayyāśem ʾet-ʾeprāyim lipnê mĕnaššeh</strong> — "he put Ephraim before Manasseh" — the deliberate reversal is formally stated: Ephraim, the younger, is given precedence — the Pentateuch's last instance of the younger-over-elder pattern that runs through the entire patriarchal narrative (Cain/Abel, Ishmael/Isaac, Esau/Jacob, Manasseh/Ephraim).</p>""",
    "21": """<p><strong>wĕʾānōkî mēt wĕhāyāh ʾĕlōhîm ʿimmākem</strong> — "I am about to die, but God will be with you (<em>ʿimmākem</em>)" — the covenant-presence formula of accompaniment (<em>ʾĕlōhîm ʿimmākem</em>) is Jacob's final comfort to Joseph: the covenant-presence that has been "with" Joseph throughout his Egyptian ordeal (39:2,21,23: "YHWH was with Joseph") will continue with the covenant-family after Jacob's death. <strong>wĕhēšîb ʾetkem ʾel-ʾereṣ ʾăḇōtêkem</strong> — "and take/bring you back (<em>wĕhēšîb</em>, Hiphil of <em>šûḇ</em>: cause to return) to the land of your fathers" — the covenant-promise of Canaan-return as the active expression of divine accompaniment.</p>""",
    "22": """<p><strong>wăʾănî nātatî lĕkā šĕkem ʾaḥad ʿal-ʾaḥêkā</strong> — "I give you one <em>šĕkem</em> more than to your brothers" — the word <em>šĕkem</em> is deliberately ambiguous: it can mean "shoulder/ridge" (a portion of land) or be the proper noun Shechem (the city). Jacob gives Joseph "one Shechem/ridge" more than the other brothers — the double meaning is likely intentional, referring to the Shechem-region land that Jacob acquired (33:19) and which became associated with Joseph's bones burial (Josh 24:32: "Joseph's bones... were buried at Shechem in the plot of ground that Jacob had bought"). <strong>ʾăšer lāqaḥtî miyyad hāʾĕmōrî bĕḥarbî ûḇĕqaštî</strong> — "which I took from the Amorites with my sword and my bow" — the military-acquisition claim creates narrative tension with ch34 (Simeon and Levi took Shechem by violence, not Jacob), possibly reflecting an independent tradition of Jacob's own military activity in the region.</p>"""
  }
}

def main():
    existing = load_comm('mkt-original', 'genesis')
    before_count = sum(len(v) for v in existing.values())
    merge_comm(existing, GENESIS_ORIGINAL)
    save_comm('mkt-original', 'genesis', existing)

    result = load_comm('mkt-original', 'genesis')
    after_count = sum(len(v) for v in result.values())
    print(f'  Verses added: {after_count - before_count}')
    for ch in [46, 47, 48]:
        ck = str(ch)
        n = len(result.get(ck, {}))
        print(f'  Ch {ch}: {n} verses present')
    total_chs = len(result)
    total_vv = sum(len(v) for v in result.values())
    print(f'  Genesis original total: {total_chs} chapters, {total_vv} verses')
    print('Genesis 46–48 mkt-original written.')

if __name__ == '__main__':
    main()
